from flask import Flask, request, redirect

app = Flask(__name__)

users = {}
cart = []
current_user = None

# 🖼 PRODUCTS WITH IMAGES
products = [
    {"id": 1, "name": "Red Kurti", "price": 700,
     "img": "data:image/jpeg;base64,"},
    {"id": 2, "name": "Blue Gown", "price": 2500,
     "img": "data:image/jpeg;base64,"},
    {"id": 3, "name": "Green Kurti", "price": 650,
     "img": "data:image/jpeg;base64,"},
    {"id": 4, "name": "Black Gown", "price": 3550,
     "img": "data:image/jpeg;base64,"}
]

# ---------------- HOME ----------------
@app.route("/")
def home():
    if not current_user:
        return redirect("/login")
    return redirect("/products")


# ---------------- SIGNUP ----------------
@app.route("/signup", methods=["GET","POST"])
def signup():

    if request.method == "POST":
        users[request.form["user"]] = request.form["pass"]
        return redirect("/login")

    return """
    <html>
    <head>
    <style>
    body{
        margin:0;
        font-family:Arial;
        background:linear-gradient(135deg,#a18cd1,#fbc2eb);
        display:flex;
        justify-content:center;
        align-items:center;
        height:100vh;
    }
    .box{
        background:white;
        padding:30px;
        border-radius:15px;
        width:300px;
        text-align:center;
        box-shadow:0 10px 20px rgba(0,0,0,0.3);
    }
    input{
        width:90%;
        padding:10px;
        margin:8px;
    }
    button{
        width:100%;
        padding:10px;
        background:black;
        color:white;
        border:none;
        border-radius:8px;
    }
    </style>
    </head>
    <body>

    <div class="box">
    <h2>📝 Signup</h2>
    <form method="POST">
    <input name="user" placeholder="Username"><br>
    <input name="pass" type="password" placeholder="Password"><br>
    <button>Signup</button>
    </form>
    <a href="/login">Login</a>
    </div>

    </body>
    </html>
    """


# ---------------- LOGIN ----------------
@app.route("/login", methods=["GET","POST"])
def login():
    global current_user

    if request.method == "POST":
        u = request.form["user"]
        p = request.form["pass"]

        if u in users and users[u] == p:
            current_user = u
            return redirect("/products")
        return "Invalid login"

    return """
    <html>
    <head>
    <style>
    body{
        margin:0;
        font-family:Arial;
        background:linear-gradient(135deg,#667eea,#764ba2);
        display:flex;
        justify-content:center;
        align-items:center;
        height:100vh;
    }
    .box{
        background:white;
        padding:30px;
        border-radius:15px;
        width:300px;
        text-align:center;
    }
    input{
        width:90%;
        padding:10px;
        margin:8px;
    }
    button{
        width:100%;
        padding:10px;
        background:black;
        color:white;
        border:none;
        border-radius:8px;
    }
    </style>
    </head>
    <body>

    <div class="box">
    <h2>🔐 Login</h2>
    <form method="POST">
    <input name="user"><br>
    <input name="pass" type="password"><br>
    <button>Login</button>
    </form>
    <a href="/signup">Signup</a>
    </div>

    </body>
    </html>
    """


# ---------------- PRODUCTS PAGE ----------------
@app.route("/products")
def show_products():
    if not current_user:
        return redirect("/login")

    html = """
    <html>
    <head>
    <style>
    body{
        margin:0;
        font-family:Arial;
        background:linear-gradient(135deg,#ffecd2,#fcb69f);
    }
    .header{
        background:black;
        color:white;
        padding:15px;
        text-align:center;
        font-size:22px;
    }
    .container{
        display:flex;
        flex-wrap:wrap;
        justify-content:center;
        padding:20px;
    }
    .card{
        background:white;
        width:220px;
        margin:15px;
        padding:15px;
        border-radius:15px;
        text-align:center;
        box-shadow:0 10px 20px rgba(0,0,0,0.2);
    }
    img{
        width:100%;
        height:220px;
        object-fit:cover;
        border-radius:10px;
    }
    button{
        width:100%;
        padding:8px;
        border:none;
        border-radius:8px;
        background:black;
        color:white;
        margin-top:5px;
    }
    .topbar{
        display:flex;
        justify-content:space-between;
        padding:10px;
        background:#333;
        color:white;
    }
    a{color:white;text-decoration:none;}
    </style>
    </head>
    <body>

    <div class="topbar">
        <div>👗 Libas Collection</div>
        <div>
            <a href="/cart">Cart</a> |
            <a href="/logout">Logout</a>
        </div>
    </div>

    <div class="header">🛍 PRODUCTS</div>

    <div class="container">
    """

    for p in products:
        html += f"""
        <div class="card">
            <img src="{p['img']}">
            <h3>{p['name']}</h3>
            <p>₹{p['price']}</p>
            <a href="/add/{p['id']}"><button>Add to Cart</button></a>
        </div>
        """

    html += """
    </div>
    </body>
    </html>
    """
    return html


# ---------------- ADD CART ----------------
@app.route("/add/<int:pid>")
def add(pid):
    for p in products:
        if p["id"] == pid:
            cart.append(p)
    return redirect("/products")


# ---------------- CART PAGE ----------------
@app.route("/cart")
def show_cart():
    total = sum(i["price"] for i in cart)

    html = """
    <html>
    <body style="font-family:Arial;background:#f1f1f1">
    <h1 style="text-align:center">🛒 CART</h1>
    <div style="text-align:center">
    """

    for c in cart:
        html += f"<p>{c['name']} - ₹{c['price']}</p>"

    html += f"""
    <h2>Total: ₹{total}</h2>
    <a href="/payment"><button style="padding:10px;background:green;color:white;border:none">Checkout</button></a>
    <a href="/clear"><button style="padding:10px;background:red;color:white;border:none">Clear Cart</button></a>
    </div>
    </body>
    </html>
    """
    return html


# ---------------- CLEAR CART ----------------
@app.route("/clear")
def clear():
    cart.clear()
    return redirect("/cart")


# ---------------- PAYMENT PAGE ----------------
@app.route("/payment")
def payment():
    total = sum(i["price"] for i in cart)

    return f"""
    <h1 style='text-align:center;margin-top:100px'>💳 Payment Page</h1>
    <h2 style='text-align:center'>Total: ₹{total}</h2>

    <form action="/success" style='text-align:center'>
    <button style='padding:10px 20px;background:green;color:white;border:none'>
    Pay Now
    </button>
    </form>
    """


# ---------------- SUCCESS ----------------
@app.route("/success")
def success():
    cart.clear()
    return "<h1 style='text-align:center;color:green;margin-top:100px'>🎉 Payment Successful!</h1>"


# ---------------- LOGOUT ----------------
@app.route("/logout")
def logout():
    global current_user
    current_user = None
    return redirect("/login")


# ---------------- RUN ----------------
if __name__ == "__main__":
    app.run(debug=True)